def range_summary(nums):
    if not nums:
        return ''

    runs = []
    start, end = None, None
    for n in sorted(set(nums)):
        if start is None:
            start = n
        elif n == end + 1:
            end = n
        else:
            runs.append(f'{start}-{end}' if start != end else str(start))
            start = n
    runs.append(str(end) if start != end else '')

    return ', '.join(runs)
